import React, { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";

const SideDrawer = () => {
  const [open, setOpen] = useState(false);
  const [profileImage, setProfileImage] = useState("");
  const navigate = useNavigate();
  const location = useLocation();

  // ✅ Check if user is logged in - CRITICAL FIX
  const token = localStorage.getItem("token");
  const userId = localStorage.getItem("userId");
  const isLoggedIn = !!token && !!userId; // Both must exist

  // Load profile image only if user is logged in
  useEffect(() => {
    if (isLoggedIn && userId) {
      const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
      setProfileImage(data.image || "");
    }
  }, [isLoggedIn, userId]);

  // Don't show any buttons on login/register pages
  const isAuthPage = location.pathname === "/login" || location.pathname === "/register";
  const isProfilePage = location.pathname === "/profile";

  // If on auth page, don't render anything
  if (isAuthPage) {
    return null;
  }

  return (
    <>
      {/* ☰ Menu Button - Only if logged in */}
      {isLoggedIn && !isProfilePage && (
        <button
          onClick={() => setOpen(!open)}
          style={{
            position: "fixed",
            top: "20px",
            left: "20px",
            zIndex: 1000,
            fontSize: "22px",
            background: "#333",
            color: "#fff",
            border: "none",
            padding: "10px 15px",
            borderRadius: "5px",
            cursor: "pointer",
          }}
        >
          ☰
        </button>
      )}

      {/* Top Right Profile Button - ONLY if logged in AND not on auth/profile pages */}
      {isLoggedIn && !isProfilePage && (
        <div
          onClick={() => navigate("/profile")}
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            zIndex: 1000,
            cursor: "pointer",
          }}
        >
          <img
            src={profileImage || "https://via.placeholder.com/50"}
            alt="Profile"
            style={{
              width: "50px",
              height: "50px",
              borderRadius: "50%",
              objectFit: "cover",
              border: "2px solid #ff6b6b",
            }}
          />
        </div>
      )}

      {/* Sidebar - Only if logged in */}
      {isLoggedIn && !isProfilePage && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: open ? "0" : "-250px",
            width: "250px",
            height: "100%",
            background: "#222",
            color: "#fff",
            paddingTop: "60px",
            transition: "0.3s",
            zIndex: 999,
          }}
        >
          <ul style={{ listStyle: "none", padding: 0 }}>
            <li 
              style={itemStyle} 
              onClick={() => { 
                navigate("/dashboard"); 
                setOpen(false); 
              }}
            >
              Dashboard
            </li>
            <li 
              style={itemStyle} 
              onClick={() => { 
                navigate("/profile"); 
                setOpen(false); 
              }}
            >
              My Profile
            </li>
            <li 
              style={itemStyle} 
              onClick={() => { 
                localStorage.removeItem("token");
                localStorage.removeItem("userId");
                localStorage.removeItem("user");
                navigate("/login");
                setOpen(false);
              }}
            >
              Logout
            </li>
          </ul>
        </div>
      )}
    </>
  );
};

const itemStyle = {
  padding: "15px",
  cursor: "pointer",
  borderBottom: "1px solid #444",
  transition: "background 0.3s",
  color: "#fff",
};

export default SideDrawer;
